using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: DataRow for inline combinations ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.1, 22.00, DisplayName = "Two items, 10% tax")]
    [DataRow(25.50, 4, 0.08, 110.16, DisplayName = "Four items, 8% tax")]
    [DataRow(0.00, 5, 0.2, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "100% tax")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for edge/error cases ---

    [TestMethod]
    [DynamicData(nameof(InvalidCalculateTotalInputs))]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        decimal unitPrice, int quantity, decimal taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, string expectedParam)>
        InvalidCalculateTotalInputs =>
    [
        (-1m,  1,   0.1m, "unitPrice"),
        (10m, -1,   0.1m, "quantity"),
        (10m,  1,  -0.1m, "taxRate"),
        (10m,  1,   1.5m, "taxRate"),
    ];

    // --- ApplyDiscount: DataRow for common scenarios ---

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off $100")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off $200")]
    [DataRow(50.00, 0.0, 50.00, DisplayName = "No discount")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% discount")]
    [DataRow(59.99, 50.0, 29.995, DisplayName = "50% off odd price")]
    public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(101.0, DisplayName = "Discount over 100%")]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(9.99, "$", "$9.99", DisplayName = "Default dollar")]
    [DataRow(1234.50, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.00, "£", "£0.00", DisplayName = "Zero pounds")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_WithDefaultSymbol_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.00m);

        Assert.StartsWith("$", result);
        Assert.Contains("42.00", result);
    }
}

